import{_ as t,o,c as i,a0 as s}from"./chunks/framework.B3sz4m_N.js";const g=JSON.parse('{"title":"Dependencies","description":"Composer, npm, paid plugins, and cost to remove or replace dependencies.","frontmatter":{"title":"Dependencies","description":"Composer, npm, paid plugins, and cost to remove or replace dependencies."},"headers":[],"relativePath":"reports/theme-only-audit-2/05-dependencies.md","filePath":"reports/theme-only-audit-2/05-dependencies.md"}'),a={name:"reports/theme-only-audit-2/05-dependencies.md"};function n(r,e,d,l,c,p){return o(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="_05-—-dependencies" tabindex="-1">05 — Dependencies <a class="header-anchor" href="#_05-—-dependencies" aria-label="Permalink to &quot;05 — Dependencies&quot;">​</a></h1><p>This document inventories every Composer + npm dependency and gives each a verdict: <strong>Keep required / Keep optional / Replace with native / Remove</strong>. It is the contract-level view of the native-first platform strategy.</p><p>All costs here reflect the work to remove or swap the dependency. Costs to migrate <em>away from</em> the functionality the dependency provides are covered in the target-document: ACF in <a href="./reports/theme-only-audit-2/02-non-native-apis.html">02</a>, Rank Math replacement in <a href="./reports/theme-only-audit-2/02-non-native-apis.html#rank-math-dependencies">02</a>, etc.</p><h2 id="contents" tabindex="-1">Contents <a class="header-anchor" href="#contents" aria-label="Permalink to &quot;Contents&quot;">​</a></h2><ul><li><a href="#verdicts-at-a-glance">Verdicts at a glance</a></li><li><a href="#composer-dependencies-root">Composer dependencies (root)</a></li><li><a href="#composer-dependencies-theme">Composer dependencies (theme)</a></li><li><a href="#npm-dependencies-production">npm dependencies (production)</a></li><li><a href="#npm-dependencies-build-only">npm dependencies (build-only)</a></li><li><a href="#upgrade-hygiene">Upgrade hygiene</a></li><li><a href="#supply-chain-observations">Supply-chain observations</a></li><li><a href="#findings-summary">Findings summary</a></li></ul><h2 id="verdicts-at-a-glance" tabindex="-1">Verdicts at a glance <a class="header-anchor" href="#verdicts-at-a-glance" aria-label="Permalink to &quot;Verdicts at a glance&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dependency</th><th>Kind</th><th>Verdict</th><th>Replacement path</th></tr></thead><tbody><tr><td><code>wpengine/advanced-custom-fields-pro</code></td><td>Composer plugin</td><td><strong>Remove</strong> (migration)</td><td>Native blocks + <code>register_post_meta</code> + Block Bindings</td></tr><tr><td><code>stoutlogic/acf-builder</code></td><td>Composer library</td><td><strong>Remove</strong> (with ACF)</td><td>N/A</td></tr><tr><td><code>jjgrainger/posttypes</code></td><td>Composer library</td><td><strong>Remove</strong></td><td>Direct <code>register_post_type()</code></td></tr><tr><td><code>jeroendesloovere/vcard</code></td><td>Composer library</td><td><strong>Remove</strong> (unused)</td><td>N/A — no usage found</td></tr><tr><td><code>gravityforms/gravityforms</code></td><td>Composer plugin</td><td><strong>Keep optional</strong></td><td>Per-project — not bundled in starter</td></tr><tr><td><code>deliciousbrains-plugin/wp-migrate-db-pro</code></td><td>Composer plugin</td><td><strong>Remove from starter</strong></td><td>WP-CLI (<code>wp db export/import</code>, <code>wp search-replace</code>)</td></tr><tr><td><code>wpackagist-plugin/seo-by-rank-math</code></td><td>Composer plugin</td><td><strong>Remove</strong> (migration)</td><td>In-theme SEO module + core sitemap + Redirection plugin</td></tr><tr><td><code>squizlabs/php_codesniffer</code></td><td>Composer dev</td><td><strong>Keep required</strong></td><td>—</td></tr><tr><td>WPML (not in composer)</td><td>Runtime plugin</td><td><strong>Keep optional</strong></td><td>Per-project — guard with <code>defined(&#39;ICL_SITEPRESS_VERSION&#39;)</code></td></tr><tr><td><code>swiper</code></td><td>npm runtime</td><td><strong>Keep optional</strong></td><td>CSS scroll-snap for simple cases; lazy-import for complex</td></tr><tr><td><code>@googlemaps/js-api-loader</code></td><td>npm runtime</td><td><strong>Keep required</strong></td><td>— (Google Maps block)</td></tr><tr><td><code>@fontsource-variable/*</code></td><td>npm runtime</td><td><strong>Keep required</strong></td><td>—</td></tr><tr><td>Custom webpack stack (40+ packages)</td><td>npm build-only</td><td><strong>Keep optional</strong></td><td>Consider <code>@wordpress/scripts</code> per-project</td></tr></tbody></table><h2 id="composer-dependencies-root" tabindex="-1">Composer dependencies (root) <a class="header-anchor" href="#composer-dependencies-root" aria-label="Permalink to &quot;Composer dependencies (root)&quot;">​</a></h2><p>Root <code>composer.json</code> declares five production requirements plus <code>dev</code> autoloader config.</p><h3 id="wpengine-advanced-custom-fields-pro-6-8-0-1" tabindex="-1"><code>wpengine/advanced-custom-fields-pro</code> <code>6.8.0.1</code> <a class="header-anchor" href="#wpengine-advanced-custom-fields-pro-6-8-0-1" aria-label="Permalink to &quot;`wpengine/advanced-custom-fields-pro` `6.8.0.1`&quot;">​</a></h3><ul><li><strong>Role</strong>: Content model + block rendering + options pages.</li><li><strong>Used by</strong>: Every block + component + CPT + option lookup — see <a href="./reports/theme-only-audit-2/02-non-native-apis.html#acf-pro-advanced-custom-fields">02 ACF-01</a> for the full coupling map.</li><li><strong>Licence</strong>: Paid annual licence via WP Engine (formerly Delicious Brains → Elliot Condon → WP Engine).</li><li><strong>Maintenance</strong>: Active; major version cadence ~annual. Breaking changes are common across majors.</li><li><strong>Verdict</strong>: <strong>Remove</strong>. Strategic direction per user direction is ACF-free native-first.</li><li><strong>Cost to remove</strong>: Multi-week engagement. See <a href="./reports/theme-only-audit-2/08-roadmap.html">08 Phase 3–4</a>.</li></ul><h3 id="gravityforms-gravityforms-2-9-31" tabindex="-1"><code>gravityforms/gravityforms</code> <code>2.9.31</code> <a class="header-anchor" href="#gravityforms-gravityforms-2-9-31" aria-label="Permalink to &quot;`gravityforms/gravityforms` `2.9.31`&quot;">​</a></h3><ul><li><strong>Role</strong>: Form builder, entry management, payment integrations.</li><li><strong>Used by</strong>: <code>inc/GravityForms.php</code>, <code>inc/Blocks/FormBlock/</code>, <code>inc/Blocks/NewsletterSignup/</code>, <code>inc/Modals.php</code>, <code>inc/ACF/ThemeOptions.php</code>.</li><li><strong>Licence</strong>: Paid annual licence.</li><li><strong>Maintenance</strong>: Active; stable release cadence. Fewer breaking changes than ACF.</li><li><strong>Verdict</strong>: <strong>Keep optional</strong>. No native equivalent with matching feature depth. Decouple from starter template.</li><li><strong>Cost to decouple</strong>: ~0.5 days — guard all usages with <code>class_exists(&#39;\\GFAPI&#39;)</code>, remove hard composer dep, document as per-project opt-in.</li></ul><h3 id="deliciousbrains-plugin-wp-migrate-db-pro-2-7-7" tabindex="-1"><code>deliciousbrains-plugin/wp-migrate-db-pro</code> <code>2.7.7</code> <a class="header-anchor" href="#deliciousbrains-plugin-wp-migrate-db-pro-2-7-7" aria-label="Permalink to &quot;`deliciousbrains-plugin/wp-migrate-db-pro` `2.7.7`&quot;">​</a></h3><ul><li><strong>Role</strong>: DB pull/push between environments via GUI.</li><li><strong>Used by</strong>: Not used in theme code — only installed as a plugin dependency.</li><li><strong>Licence</strong>: Paid annual licence.</li><li><strong>Maintenance</strong>: Active.</li><li><strong>Verdict</strong>: <strong>Remove from starter</strong>. WP-CLI (<code>wp db export</code>, <code>wp db import</code>, <code>wp search-replace</code>) covers 95% of the functionality.</li><li><strong>Cost to remove</strong>: 0 — just drop from <code>composer.json</code>.</li><li><strong>Team workflow impact</strong>: Document WP-CLI equivalents in the starter README. For projects where the team values the GUI, reinstate per-project.</li></ul><h3 id="wpackagist-plugin-seo-by-rank-math-1-0-268" tabindex="-1"><code>wpackagist-plugin/seo-by-rank-math</code> <code>1.0.268</code> <a class="header-anchor" href="#wpackagist-plugin-seo-by-rank-math-1-0-268" aria-label="Permalink to &quot;`wpackagist-plugin/seo-by-rank-math` `1.0.268`&quot;">​</a></h3><ul><li><strong>Role</strong>: SEO (schema.org, meta tags, sitemaps, redirects, breadcrumbs, analytics).</li><li><strong>Used by</strong>: <code>inc/RankMath.php</code> (excerpt compat filter), <code>inc/Blocks/Breadcrumbs/Breadcrumbs.php</code> (optional integration), <code>inc/Admin.php</code> (dashboard widget removal).</li><li><strong>Licence</strong>: Free (with paid Pro upgrade for advanced features).</li><li><strong>Maintenance</strong>: Active but rough — major releases frequently break template integrations and custom variables.</li><li><strong>Verdict</strong>: <strong>Remove (migration)</strong>. Replace with ~300 lines of in-theme SEO module + core&#39;s native sitemap + <a href="https://wordpress.org/plugins/redirection/" target="_blank" rel="noreferrer">Redirection</a> plugin for URL redirects.</li><li><strong>Cost to replace</strong>: 2–3 engineer-days for the SEO module + per-project tuning.</li></ul><h2 id="composer-dependencies-theme" tabindex="-1">Composer dependencies (theme) <a class="header-anchor" href="#composer-dependencies-theme" aria-label="Permalink to &quot;Composer dependencies (theme)&quot;">​</a></h2><p>Theme-level <code>composer.json</code>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;require&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;stoutlogic/acf-builder&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;^1.12&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;jeroendesloovere/vcard&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1.7.4&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;jjgrainger/posttypes&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;^2.2&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="stoutlogic-acf-builder-1-12" tabindex="-1"><code>stoutlogic/acf-builder</code> <code>^1.12</code> <a class="header-anchor" href="#stoutlogic-acf-builder-1-12" aria-label="Permalink to &quot;`stoutlogic/acf-builder` `^1.12`&quot;">​</a></h3><ul><li><strong>Role</strong>: Fluent PHP builder for ACF field group arrays.</li><li><strong>Used by</strong>: Every block, every component, every ACF group, every CPT/taxonomy field.</li><li><strong>Licence</strong>: MIT.</li><li><strong>Maintenance</strong>: Moderate. Last release 2024. ~1k GitHub stars.</li><li><strong>Verdict</strong>: <strong>Remove</strong> (with ACF).</li><li><strong>Cost</strong>: Removed as a side effect of ACF migration.</li></ul><h3 id="jeroendesloovere-vcard-1-7-4" tabindex="-1"><code>jeroendesloovere/vcard</code> <code>1.7.4</code> <a class="header-anchor" href="#jeroendesloovere-vcard-1-7-4" aria-label="Permalink to &quot;`jeroendesloovere/vcard` `1.7.4`&quot;">​</a></h3><ul><li><strong>Role</strong>: vCard file generation (RFC 2426 / RFC 6350).</li><li><strong>Used by</strong>: <strong>None</strong>. No <code>jeroendesloovere\\VCard\\VCard</code> import found anywhere in the codebase. This is an unused dependency.</li><li><strong>Licence</strong>: MIT.</li><li><strong>Maintenance</strong>: Stable, infrequent updates.</li><li><strong>Verdict</strong>: <strong>Remove (unused)</strong>.</li><li><strong>Cost</strong>: 5 minutes — <code>composer remove jeroendesloovere/vcard</code>.</li></ul><p><strong>Finding <code>DEPS-VCARD-01</code> (P2, S).</strong> Remove unused <code>jeroendesloovere/vcard</code> dependency.</p><h3 id="jjgrainger-posttypes-2-2" tabindex="-1"><code>jjgrainger/posttypes</code> <code>^2.2</code> <a class="header-anchor" href="#jjgrainger-posttypes-2-2" aria-label="Permalink to &quot;`jjgrainger/posttypes` `^2.2`&quot;">​</a></h3><ul><li><strong>Role</strong>: Fluent builder for <code>register_post_type()</code> / <code>register_taxonomy()</code>.</li><li><strong>Used by</strong>: <code>inc/PostTypes/*.php</code>, <code>inc/Taxonomies/*.php</code>.</li><li><strong>Licence</strong>: MIT.</li><li><strong>Maintenance</strong>: Minimal, sparse. Last release ~2 years old.</li><li><strong>Verdict</strong>: <strong>Remove</strong>. Direct calls to <code>register_post_type()</code> are not significantly more verbose and are the native pattern.</li><li><strong>Cost</strong>: ~0.5 days — mechanical rewrite of 4 CPTs + 1 taxonomy.</li></ul><p>Covered in detail in <a href="./reports/theme-only-audit-2/02-non-native-apis.html#jjgraingerposttypes">02 POSTTYPES-01</a>.</p><h3 id="squizlabs-php-codesniffer-3" tabindex="-1"><code>squizlabs/php_codesniffer</code> <code>3.*</code> <a class="header-anchor" href="#squizlabs-php-codesniffer-3" aria-label="Permalink to &quot;`squizlabs/php_codesniffer` `3.*`&quot;">​</a></h3><ul><li><strong>Role</strong>: PHP_CodeSniffer — linter.</li><li><strong>Used by</strong>: <code>composer run lint:php</code>.</li><li><strong>Licence</strong>: BSD-3.</li><li><strong>Maintenance</strong>: Active.</li><li><strong>Verdict</strong>: <strong>Keep required</strong>.</li><li><strong>Note</strong>: Pin a minor version — <code>3.*</code> is too broad. Current major is 3.10; 3.11/3.12 may contain rule changes. Pin to <code>^3.10.0</code> or specific-minor.</li></ul><p><strong>Finding <code>DEPS-PHPCS-01</code> (P2, S).</strong> Pin <code>squizlabs/php_codesniffer</code> to a specific minor version.</p><h2 id="npm-dependencies-production" tabindex="-1">npm dependencies (production) <a class="header-anchor" href="#npm-dependencies-production" aria-label="Permalink to &quot;npm dependencies (production)&quot;">​</a></h2><p>From theme-level <code>package.json</code> → <code>dependencies</code>:</p><h3 id="swiper-12-0-3" tabindex="-1"><code>swiper</code> <code>^12.0.3</code> <a class="header-anchor" href="#swiper-12-0-3" aria-label="Permalink to &quot;`swiper` `^12.0.3`&quot;">​</a></h3><ul><li><strong>Role</strong>: Touch-enabled carousel / slider JS library.</li><li><strong>Bundle size</strong>: ~150KB gzipped (min).</li><li><strong>Licence</strong>: MIT.</li><li><strong>Maintenance</strong>: Active, well-maintained.</li><li><strong>Verdict</strong>: <strong>Keep optional</strong>. See <a href="./reports/theme-only-audit-2/02-non-native-apis.html#swiper">02 SWIPER-02</a> for lazy-import / CSS scroll-snap replacement strategies.</li></ul><h3 id="googlemaps-js-api-loader-2-0-2" tabindex="-1"><code>@googlemaps/js-api-loader</code> <code>^2.0.2</code> <a class="header-anchor" href="#googlemaps-js-api-loader-2-0-2" aria-label="Permalink to &quot;`@googlemaps/js-api-loader` `^2.0.2`&quot;">​</a></h3><ul><li><strong>Role</strong>: Loader for the Google Maps JavaScript API.</li><li><strong>Used by</strong>: <code>inc/Blocks/Map/</code> — the Map block JS.</li><li><strong>Licence</strong>: Apache 2.0.</li><li><strong>Maintenance</strong>: Google-maintained.</li><li><strong>Verdict</strong>: <strong>Keep required</strong> for projects that use the Map block. Consider making the Map block itself optional per-project (not every site needs Google Maps).</li></ul><h3 id="fontsource-variable-ibm-plex-sans-fontsource-variable-open-sans" tabindex="-1"><code>@fontsource-variable/ibm-plex-sans</code> + <code>@fontsource-variable/open-sans</code> <a class="header-anchor" href="#fontsource-variable-ibm-plex-sans-fontsource-variable-open-sans" aria-label="Permalink to &quot;`@fontsource-variable/ibm-plex-sans` + `@fontsource-variable/open-sans`&quot;">​</a></h3><ul><li><strong>Role</strong>: Self-hosted variable fonts (IBM Plex Sans, Open Sans).</li><li><strong>Used by</strong>: Font stack, webpack asset pipeline.</li><li><strong>Licence</strong>: OFL (Open Font Licence).</li><li><strong>Maintenance</strong>: Active community.</li><li><strong>Verdict</strong>: <strong>Keep required</strong>. Self-hosting is the right choice (GDPR-friendly, no Google Fonts call).</li><li><strong>Note</strong>: See <a href="./reports/theme-only-audit-2/03-performance.html#font-loading">03 PERF-FONT-02</a> — subset to latin-only if applicable.</li></ul><h2 id="npm-dependencies-build-only" tabindex="-1">npm dependencies (build-only) <a class="header-anchor" href="#npm-dependencies-build-only" aria-label="Permalink to &quot;npm dependencies (build-only)&quot;">​</a></h2><p>The <code>devDependencies</code> block is ~40 packages — a typical modern webpack theme setup. Highlights:</p><table tabindex="0"><thead><tr><th>Package</th><th>Role</th><th>Verdict</th></tr></thead><tbody><tr><td><code>webpack</code>, <code>webpack-cli</code>, <code>webpack-dev-server</code></td><td>Bundler</td><td>Keep</td></tr><tr><td><code>@babel/core</code>, <code>@babel/preset-env</code>, <code>babel-loader</code></td><td>JS transpilation</td><td>Keep</td></tr><tr><td><code>sass</code>, <code>sass-loader</code>, <code>postcss-scss</code>, <code>postcss-loader</code></td><td>SCSS pipeline</td><td>Keep</td></tr><tr><td><code>css-loader</code>, <code>mini-css-extract-plugin</code></td><td>CSS extraction</td><td>Keep</td></tr><tr><td><code>css-minimizer-webpack-plugin</code>, <code>terser-webpack-plugin</code></td><td>Minification</td><td>Keep</td></tr><tr><td><code>image-minimizer-webpack-plugin</code>, <code>sharp</code></td><td>Image optimisation</td><td>Keep</td></tr><tr><td><code>svg-spritemap-webpack-plugin</code></td><td>SVG sprite gen</td><td>Keep</td></tr><tr><td><code>webpack-favicons</code>, <code>favicons</code></td><td>Favicon generation</td><td>Keep</td></tr><tr><td><code>html-webpack-plugin</code></td><td>HTML output</td><td>Check — theme doesn&#39;t obviously use this</td></tr><tr><td><code>clean-webpack-plugin</code></td><td>Output cleanup</td><td>Keep</td></tr><tr><td><code>copy-webpack-plugin</code></td><td>Static asset copy</td><td>Keep</td></tr><tr><td><code>webpack-manifest-plugin</code></td><td>Manifest generation</td><td>Keep (see <a href="./reports/theme-only-audit-2/03-performance.html#asset-versioning-filemtime-vs-manifest">03 ASSET-VER-01</a>)</td></tr><tr><td><code>stylelint-*</code> (7 packages)</td><td>SCSS linting</td><td>Keep</td></tr><tr><td><code>stylelint-webpack-plugin</code></td><td>In-build linting</td><td>Keep</td></tr><tr><td><code>prettier</code></td><td>Formatting</td><td>Keep</td></tr><tr><td><code>husky</code></td><td>Git hooks</td><td>Keep</td></tr><tr><td><code>cross-env</code></td><td>Env-var setting</td><td>Keep</td></tr></tbody></table><h3 id="html-webpack-plugin" tabindex="-1"><code>html-webpack-plugin</code> <a class="header-anchor" href="#html-webpack-plugin" aria-label="Permalink to &quot;`html-webpack-plugin`&quot;">​</a></h3><p>Configured but not obviously used. Theme doesn&#39;t emit HTML files. Candidate for removal.</p><p><strong>Finding <code>DEPS-HTMLWP-01</code> (P2, S).</strong> Verify <code>html-webpack-plugin</code> is actually needed; remove if not.</p><h3 id="wordpress-scripts-alternative" tabindex="-1"><code>@wordpress/scripts</code> alternative <a class="header-anchor" href="#wordpress-scripts-alternative" aria-label="Permalink to &quot;`@wordpress/scripts` alternative&quot;">​</a></h3><p>Every modern native-block WP theme uses <code>@wordpress/scripts</code> for its build. It bundles webpack, Babel (with JSX + WordPress&#39;s React), ESLint config, scripts config, etc. — in a single <code>npm i @wordpress/scripts</code> + <code>wp-scripts build</code>.</p><p>The custom webpack stack here is ~40 packages vs <code>@wordpress/scripts</code>&#39; single dep. Trade-offs:</p><ul><li><strong>Current stack</strong> — familiar, flexible. Works for non-block JS (like the front-end <code>scripts.js</code> entry). The block + SCSS discovery pattern in <code>buildEntryPoints()</code> is a genuine asset.</li><li><strong><code>@wordpress/scripts</code></strong> — standard WordPress tooling. Built-in JSX/Gutenberg support. Less configuration. Handles block.json auto-discovery. Opinionated output structure matches other WP dev.</li></ul><p>For the native block migration (Phase 3 in <a href="./reports/theme-only-audit-2/08-roadmap.html">08</a>), <code>@wordpress/scripts</code> is the canonical choice. For the existing non-block JS (<code>scripts.js</code>, <code>modal.js</code>, <code>lazyload.js</code>, <code>mobile-menu.js</code>, etc.), the current webpack works fine.</p><p><strong>Finding <code>DEPS-WP-SCRIPTS-01</code> (P2, M).</strong> When beginning native block migration, evaluate whether to run <code>@wordpress/scripts</code> alongside the existing webpack (dual-build — <code>wp-scripts</code> for blocks, custom webpack for everything else), or migrate everything to <code>@wordpress/scripts</code>. I&#39;d suggest dual-build: per-block JS under <code>@wordpress/scripts</code>, main bundles continuing through current webpack.</p><h2 id="upgrade-hygiene" tabindex="-1">Upgrade hygiene <a class="header-anchor" href="#upgrade-hygiene" aria-label="Permalink to &quot;Upgrade hygiene&quot;">​</a></h2><h3 id="composer-json-root-and-theme-minimum-stability-dev" tabindex="-1"><code>composer.json</code> (root and theme): <code>minimum-stability: dev</code> <a class="header-anchor" href="#composer-json-root-and-theme-minimum-stability-dev" aria-label="Permalink to &quot;`composer.json` (root and theme): `minimum-stability: dev`&quot;">​</a></h3><p>Both <code>composer.json</code> files declare:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;minimum-stability&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;dev&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;prefer-stable&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><p><code>minimum-stability: dev</code> + <code>prefer-stable: true</code> means &quot;allow dev-tagged packages but prefer stable ones when available&quot;. In practice, this is fine — WP-specific packages sometimes only have dev-* tagged versions. But:</p><ul><li>Newly added packages without stable releases will silently install <code>dev-master</code> / <code>dev-main</code>.</li><li>Dependency resolution gets more expensive (Composer has to consider more version combinations).</li></ul><p><strong>Finding <code>DEPS-STABILITY-01</code> (P2, S).</strong> Consider <code>minimum-stability: stable</code> for the theme-level <code>composer.json</code> (which has no dev-only deps), and keep <code>dev</code> for the root (which has WPMDB Pro and similar that sometimes use dev-master).</p><h3 id="no-lock-files-in-ci-audit" tabindex="-1">No lock files in CI audit <a class="header-anchor" href="#no-lock-files-in-ci-audit" aria-label="Permalink to &quot;No lock files in CI audit&quot;">​</a></h3><p><code>composer.lock</code> and <code>pnpm-lock.yaml</code> are committed — good. But there&#39;s no CI step that runs <code>composer audit</code> or <code>npm audit</code> / <code>pnpm audit</code> for known-vulnerability scanning.</p><p><strong>Finding <code>DEPS-AUDIT-01</code> (P2, S).</strong> Add <code>composer audit</code> + <code>pnpm audit</code> to CI. Fail the build on HIGH/CRITICAL vulnerabilities; warn on moderate.</p><h3 id="renovate-dependabot" tabindex="-1">Renovate / Dependabot <a class="header-anchor" href="#renovate-dependabot" aria-label="Permalink to &quot;Renovate / Dependabot&quot;">​</a></h3><p>No <code>.github/dependabot.yml</code> or <code>renovate.json</code>. Dependency updates are manual.</p><p><strong>Finding <code>DEPS-RENOVATE-01</code> (P2, S).</strong> Add Dependabot or Renovate config. Auto-PRs for patch/minor updates. Pinned major updates.</p><h2 id="supply-chain-observations" tabindex="-1">Supply-chain observations <a class="header-anchor" href="#supply-chain-observations" aria-label="Permalink to &quot;Supply-chain observations&quot;">​</a></h2><h3 id="private-composer-repos" tabindex="-1">Private Composer repos <a class="header-anchor" href="#private-composer-repos" aria-label="Permalink to &quot;Private Composer repos&quot;">​</a></h3><p>Both <code>composer.json</code> files declare custom VCS / Composer repos:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;repositories&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    {</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;composer&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;url&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://wpackagist.org&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">},</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    {</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;composer&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;url&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://connect.advancedcustomfields.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">},</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    {</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;composer&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;url&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://premium.wpmudev.org/&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">},</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    {</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;composer&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;url&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://composer.deliciousbrains.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">},</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    {</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;composer&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;url&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://my.yoast.com/packages/&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><ul><li><code>wpackagist.org</code> — public.</li><li><code>connect.advancedcustomfields.com</code> — ACF Pro paid. Requires <code>.env</code> var for auth.</li><li><code>premium.wpmudev.org</code> — WPMU DEV; not obviously used in this theme&#39;s deps. Consider removing.</li><li><code>composer.deliciousbrains.com</code> — WPMDB Pro.</li><li><code>my.yoast.com/packages/</code> — Yoast; not used.</li></ul><p><strong>Finding <code>DEPS-REPOS-01</code> (P2, S).</strong> Prune unused custom Composer repos. Each adds network calls to <code>composer update</code> and is a supply-chain surface. Keep only the repos actually used.</p><h3 id="gravity-forms-via-wp-plugin-gf-key-env-interpolation" tabindex="-1">Gravity Forms via <code>{%WP_PLUGIN_GF_KEY}</code> env interpolation <a class="header-anchor" href="#gravity-forms-via-wp-plugin-gf-key-env-interpolation" aria-label="Permalink to &quot;Gravity Forms via `{%WP_PLUGIN_GF_KEY}` env interpolation&quot;">​</a></h3><p>Root <code>composer.json:39-48</code>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;dist&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;zip&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;url&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://www.gravityhelp.com/wp-content/plugins/gravitymanager/api.php?op=get_plugin&amp;slug=gravityforms&amp;key={%WP_PLUGIN_GF_KEY}&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>The <code>{%VAR}</code> syntax is from <code>ffraenz/private-composer-installer</code>. Requires <code>WP_PLUGIN_GF_KEY</code> in env at install time. Good pattern — keeps the licence key out of <code>composer.json</code>. Document prominently in the README.</p><h3 id="auth-json-handling" tabindex="-1">Auth.json handling <a class="header-anchor" href="#auth-json-handling" aria-label="Permalink to &quot;Auth.json handling&quot;">​</a></h3><p>The starter README says &quot;Add auth.json file to the root directory. This can be found in 1password.&quot; This is the standard approach, but:</p><ul><li><code>auth.json</code> is in <code>.gitignore</code> — correct.</li><li>There&#39;s no documentation on where specifically 1Password — in a larger team this causes friction at onboarding.</li></ul><p><strong>Finding <code>DEPS-AUTH-01</code> (P2, S).</strong> Document <code>auth.json</code> structure + expected keys + 1Password vault / item path in the README.</p><h2 id="findings-summary" tabindex="-1">Findings summary <a class="header-anchor" href="#findings-summary" aria-label="Permalink to &quot;Findings summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ID</th><th>Title</th><th>Severity</th><th>Effort</th></tr></thead><tbody><tr><td>DEPS-VCARD-01</td><td>Remove unused <code>jeroendesloovere/vcard</code></td><td>P2</td><td>S</td></tr><tr><td>DEPS-PHPCS-01</td><td>Pin <code>squizlabs/php_codesniffer</code> to minor version</td><td>P2</td><td>S</td></tr><tr><td>DEPS-HTMLWP-01</td><td>Remove <code>html-webpack-plugin</code> if unused</td><td>P2</td><td>S</td></tr><tr><td>DEPS-WP-SCRIPTS-01</td><td>Evaluate <code>@wordpress/scripts</code> for native-block migration</td><td>P2</td><td>M</td></tr><tr><td>DEPS-STABILITY-01</td><td>Tighten <code>minimum-stability</code> at theme level</td><td>P2</td><td>S</td></tr><tr><td>DEPS-AUDIT-01</td><td>Add <code>composer audit</code> / <code>pnpm audit</code> to CI</td><td>P2</td><td>S</td></tr><tr><td>DEPS-RENOVATE-01</td><td>Enable Dependabot or Renovate</td><td>P2</td><td>S</td></tr><tr><td>DEPS-REPOS-01</td><td>Prune unused custom Composer repos</td><td>P2</td><td>S</td></tr><tr><td>DEPS-AUTH-01</td><td>Document <code>auth.json</code> setup + vault location</td><td>P2</td><td>S</td></tr></tbody></table><p>Next: <a href="./reports/theme-only-audit-2/06-blocks-and-components.html">06 — Blocks and Components (exhaustive)</a></p>',81)])])}const u=t(a,[["render",n]]);export{g as __pageData,u as default};
